first = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
first = imresize(rgb2gray(first), [120 160]);
second = imread(fullpath(getIPCVpath() + "/images/opencv_left02.jpg"));
second = imresize(rgb2gray(second), [120 160]);
flow = imopticalflow(first, second);
subplot(1, 2, 1);
imshow(first);
subplot(1, 2, 2);
imshow(second);
disp(size(flow(1)));
